    int n = roots.size();
    vector<ll> coeff(n+1, 0);
    coeff[0] = 1; // x^n的系数
    for(int i = 0; i < n; i++) {
        for(int j = i; j >= 0; j--) {
            coeff[j+1] += coeff[j] * roots[i];
        }
    }
    return coeff;
}

