    vector<double> roots;
    double D = B*B - 4.0*A*C;
    if(abs(D) < 1e-12) {
        roots.push_back(-B/(2.0*A));
    } else if(D > 0) {
        roots.push_back((-B - sqrt(D))/(2.0*A));
        roots.push_back((-B + sqrt(D))/(2.0*A));
        sort(roots.begin(), roots.end());
    }
    return roots;
}

