void init_comb(int n) {
    comb.assign(n+1, vector<ll>(n+1, 0));
    for(int i=0; i<=n; i++) {
        comb[i][0] = comb[i][i] = 1;
        for(int j=1; j<i; j++)
            comb[i][j] = (comb[i-1][j-1] + comb[i-1][j]) % MOD;
    }
}

// 3. 概率DP框架
