    // 注意：游戏问题可能需要考虑双方最优策略
}

// 4. 博弈论判断（Nim类游戏）
bool isWinningState(vector<int>& piles) {
    int xor_sum = 0;
    for(int x : piles) xor_sum ^= x;
    return xor_sum != 0; // 非零则先手必胜
}

// 5. 路径计数（网格DP）
int countPaths(int n, int m) {
    vector<vector<ll>> dp(n+1, vector<ll>(m+1, 0));
    dp[1][1] = 1;
    for(int i=1; i<=n; i++)
        for(int j=1; j<=m; j++)
            if(i>1 || j>1)
                dp[i][j] = (dp[i-1][j] + dp[i][j-1]) % MOD;
    return dp[n][m];
}

