// 几何优化与扫描线通用模板框架
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
typedef pair<int, int> pii;

// 核心数据结构：事件点结构体
struct Event {
    int x;          // 事件发生坐标（通常为x坐标）
    int type;       // 事件类型：+1表示开始，-1表示结束
    int id;         // 关联的对象ID
    // 可根据需要添加其他参数：y坐标、权重值等

    // 排序规则：先按x坐标，再按type（结束事件优先处理）
    bool operator<(const Event& other) const {
        if (x != other.x) return x < other.x;
        return type > other.type;  // 结束事件type=-1，优先处理
    }
};

// 扫描线主函数框架
void sweepLine(vector<Event>& events) {
    sort(events.begin(), events.end());

    // 活动集合：存储当前扫描线穿过的对象
    set<int> activeSet;  // 或multiset、线段树等数据结构
    // 可能需要维护其他信息：最大最小值、区间和等

    ll ans = 0;
    int prevX = events[0].x;

    for (const Event& e : events) {
        // 处理扫描线移动带来的贡献
        if (!activeSet.empty()) {
            // 计算从prevX到e.x区间内活动对象的贡献
            int width = e.x - prevX;
            // 根据活动集合计算高度/数量等
            // ans += width * currentHeight;
        }

        // 更新活动集合
        if (e.type == 1) {
            // 开始事件：加入活动集合
            activeSet.insert(e.id);
        } else {
            // 结束事件：移出活动集合
            activeSet.erase(e.id);
        }

        prevX = e.x;
    }

    cout << ans << endl;
}

// 几何计算辅助函数
ll crossProduct(pii a, pii b, pii c) {
    return (ll)(b.first - a.first) * (c.second - a.second) 
           - (ll)(b.second - a.second) * (c.first - a.first);
}

// 凸包扫描（Andrew's monotone chain）
vector<pii> convexHull(vector<pii>& points) {
    sort(points.begin(), points.end());
    vector<pii> hull;

    // 下凸包
    for (auto& p : points) {
        while (hull.size() >= 2 && 
               crossProduct(hull[hull.size()-2], hull.back(), p) <= 0)
            hull.pop_back();
        hull.push_back(p);
    }

    // 上凸包
    int lowerSize = hull.size();
    for (int i = points.size()-2; i >= 0; i--) {
        while (hull.size() > lowerSize && 
               crossProduct(hull[hull.size()-2], hull.back(), points[i]) <= 0)
            hull.pop_back();
        hull.push_back(points[i]);
    }

    hull.pop_back();  // 移除重复的起点
    return hull;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 数据输入
    int n;
    cin >> n;

    // 构建事件点
    vector<Event> events;
    for (int i = 0; i < n; i++) {
        int x1, y1, x2, y2;
        cin >> x1 >> y1 >> x2 >> y2;
        events.push_back({x1, 1, i});   // 开始事件
        events.push_back({x2, -1, i});  // 结束事件
    }

    // 执行扫描线算法
    sweepLine(events);

    return 0;
}

// 几何变换与投影通用模板
#include <bits/stdc++.h>
using namespace std;
using ld = long double;
const ld PI = acos(-1.0L);
const ld EPS = 1e-12;

// 基础点/向量结构
struct Point {
    ld x, y;
    Point(ld x = 0, ld y = 0) : x(x), y(y) {}
    Point operator+(const Point &p) const { return Point(x + p.x, y + p.y); }
    Point operator-(const Point &p) const { return Point(x - p.x, y - p.y); }
    Point operator*(ld k) const { return Point(x * k, y * k); }
    Point operator/(ld k) const { return Point(x / k, y / k); }
    ld dot(const Point &p) const { return x * p.x + y * p.y; }          // 点积
    ld cross(const Point &p) const { return x * p.y - y * p.x; }       // 叉积
    ld len2() const { return x * x + y * y; }                         // 长度平方
    ld len() const { return sqrt(len2()); }                           // 长度
    Point rotate(ld angle) const {                                    // 绕原点逆时针旋转
        ld c = cos(angle), s = sin(angle);
        return Point(x * c - y * s, x * s + y * c);
    }
    Point norm() const { ld l = len(); return l > EPS ? *this / l : *this; } // 单位化
    bool operator==(const Point &p) const { return fabs(x - p.x) < EPS && fabs(y - p.y) < EPS; }
};

// 直线/线段表示
struct Line {
    Point p, v; // 点向式: p + t*v
    Line(Point a, Point b) : p(a), v(b - a) {}
};

// 投影: 点p到直线l的投影点
Point project(Point p, Line l) {
    return l.p + l.v * (l.v.dot(p - l.p) / l.v.len2());
}

// 反射: 点p关于直线l的对称点
Point reflect(Point p, Line l) {
    Point proj = project(p, l);
    return proj * 2 - p;
}

// 判断点是否在线段上
bool onSegment(Point p, Point a, Point b) {
    return fabs((a - p).cross(b - p)) < EPS && (a - p).dot(b - p) <= EPS;
}

// 坐标变换: 旋转/缩放/平移
Point transform(Point p, ld angle, ld scale, Point translate) {
    return p.rotate(angle) * scale + translate;
}

