// 1. 进制转换函数
long long toDecimal(const string &num, int base) {
    long long res = 0;
    for (char c : num) {
        int digit = (c >= '0' && c <= '9') ? (c - '0') : (c - 'A' + 10);
        res = res * base + digit;
    }
    return res;
}

string fromDecimal(long long num, int base) {
    if (num == 0) return "0";
    string res;
    while (num > 0) {
        int digit = num % base;
        res += (digit < 10) ? ('0' + digit) : ('A' + digit - 10);
        num /= base;
    }
    reverse(res.begin(), res.end());
    return res;
}

