        fact[i] = fact[i - 1] * i % MOD;
    }
    invFact[n] = modPow(fact[n], MOD - 2, MOD);
    for (int i = n - 1; i >= 0; i--) {
        invFact[i] = invFact[i + 1] * (i + 1) % MOD;
    }
}

long long nCk(int n, int k) {
    if (k < 0 || k > n) return 0;
    return fact[n] * invFact[k] % MOD * invFact[n - k] % MOD;
}

// 质因数分解
vector<pair<int, int>> factorize(int x) {
    vector<pair<int, int>> factors;
    for (int i = 2; i * i <= x; i++) {
        if (x % i == 0) {
            int cnt = 0;
            while (x % i == 0) {
                x /= i;
                cnt++;
            }
            factors.push_back({i, cnt});
        }
    }
    if (x > 1) factors.push_back({x, 1});
    return factors;
}

// 容斥原理辅助函数
long long inclusionExclusion(int n, vector<int> &primes) {
    long long ans = 0;
    int m = primes.size();
    for (int mask = 1; mask < (1 << m); mask++) {
        long long prod = 1;
        int bits = 0;
        for (int i = 0; i < m; i++) {
            if (mask >> i & 1) {
                prod *= primes[i];
                bits++;
            }
        }
        long long cnt = n / prod;
        if (bits % 2 == 1) ans += cnt;
        else ans -= cnt;
    }
    return ans;
}

