// 多项式长除法模板
// 假设多项式用 vector<double> 表示，下标从低次到高次
vector<double> poly_division(const vector<double>& P, const vector<double>& Q) {
    int n = P.size() - 1; // deg(P)
    int m = Q.size() - 1; // deg(Q)
    if (n < m) {
        // 当 deg(P) < deg(Q) 时，商为0，余数为P
        return vector<double>(1, 0.0); // 商
        // 余数直接返回P
    }
    vector<double> R = P; // 余数初始化
    vector<double> S(n - m + 1, 0.0); // 商，次数为 n-m
    for (int k = n - m; k >= 0; k--) {
        // 计算商 S[k]
        S[k] = R[m + k] / Q[m];
        // 更新余数
        for (int j = 0; j <= m; j++) {
            R[k + j] -= S[k] * Q[j];
        }
    }
    // 此时 R 中只有前 m 项有效（次数小于 m）
    R.resize(m); // 调整余数大小
    return S; // 返回商
}

// 多项式乘法（卷积）辅助函数
vector<double> poly_multiply(const vector<double>& A, const vector<double>& B) {
    int n = A.size(), m = B.size();
    vector<double> C(n + m - 1, 0.0);
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++)
            C[i + j] += A[i] * B[j];
    return C;
}

// 多项式加法
vector<double> poly_add(const vector<double>& A, const vector<double>& B) {
    int n = max(A.size(), B.size());
    vector<double> C(n, 0.0);
    for (int i = 0; i < A.size(); i++) C[i] += A[i];
    for (int i = 0; i < B.size(); i++) C[i] += B[i];
    return C;
}

