// 核心函数：判断当前状态是否为必胜态
bool isWinningState(const vector<int>& state, int player) {
    // 1. 记忆化搜索/DP表
    static map<vector<int>, bool> memo;
    if (memo.count(state)) return memo[state];

    // 2. 检查终止条件（游戏结束状态）
    if (isTerminal(state)) {
        return memo[state] = (getWinner(state) == player);
    }

    // 3. 生成所有合法移动
    vector<vector<int>> nextStates = generateMoves(state, player);

    // 4. 博弈逻辑判断
    if (player == 0) { // 当前玩家（通常为Alice/先手）
        // 存在一个移动使得对手必败
        for (auto& next : nextStates) {
            if (!isWinningState(next, 1)) {
                return memo[state] = true;
            }
        }
        return memo[state] = false;
    } else { // 对手玩家
        // 所有移动都会让当前玩家必胜
        for (auto& next : nextStates) {
            if (isWinningState(next, 0)) {
                return memo[state] = false;
            }
        }
        return memo[state] = true;
    }
}

// 概率游戏变体：计算期望值
double expectedValue(const vector<int>& state) {
    // 1. 记忆化
    static map<vector<int>, double> memo;
    if (memo.count(state)) return memo[state];

    // 2. 终止条件
    if (isTerminal(state)) {
        return memo[state] = getTerminalValue(state);
    }

    // 3. 状态转移
    vector<pair<vector<int>, double>> transitions = getTransitions(state);
    double exp = 0.0;
    for (auto& [next, prob] : transitions) {
        exp += prob * expectedValue(next);
    }
    return memo[state] = exp;
}

