Matrix matMul(const Matrix &A, const Matrix &B, ll mod) {
    int n = A.size();
    Matrix C(n, vector<ll>(n, 0));
    for (int i = 0; i < n; i++)
        for (int k = 0; k < n; k++)
            if (A[i][k])
                for (int j = 0; j < n; j++)
                    C[i][j] = (C[i][j] + A[i][k] * B[k][j]) % mod;
    return C;
}

Matrix matPow(Matrix base, ll power, ll mod) {
    int n = base.size();
    Matrix res(n, vector<ll>(n, 0));
    for (int i = 0; i < n; i++) res[i][i] = 1;
    while (power) {
        if (power & 1) res = matMul(res, base, mod);
        base = matMul(base, base, mod);
        power >>= 1;
    }
    return res;
}

