        return res;
    }
    // 矩阵乘法（模MOD）
    Matrix operator*(const Matrix& other) const {
        assert(m == other.n);
        Matrix res(n, other.m);
        for (int i = 0; i < n; i++)
            for (int k = 0; k < m; k++)
                if (a[i][k])
                    for (int j = 0; j < other.m; j++)
                        res.a[i][j] = (res.a[i][j] + a[i][k] * other.a[k][j]) % MOD;
        return res;
    }
    // 矩阵快速幂
    Matrix pow(ll k) const {
        assert(n == m);
        Matrix base = *this, res = eye(n);
        while (k) {
            if (k & 1) res = res * base;
            base = base * base;
            k >>= 1;
        }
        return res;
    }
};

// 线性递推求解函数（以k阶递推为例）
// coeff: 递推系数向量[c1, c2, ..., ck]，满足 a_n = sum_{i=1..k} c_i * a_{n-i}
// init: 初始值向量[a_{k-1}, a_{k-2}, ..., a_0]
// n: 目标项数（求a_n）
ll linear_recurrence(const vector<ll>& coeff, const vector<ll>& init, ll n) {
    int k = coeff.size();
    if (n < k) return init[k - 1 - n]; // 注意顺序
    // 构建转移矩阵 T (k x k)
    Matrix T(k, k);
    for (int i = 0; i < k; i++) T.a[0][i] = coeff[i];
    for (int i = 1; i < k; i++) T.a[i][i - 1] = 1;
    // 初始向量 F = [a_{k-1}, a_{k-2}, ..., a_0]^T
    Matrix F(k, 1);
    for (int i = 0; i < k; i++) F.a[i][0] = init[i];
    // 计算 T^{n - (k-1)} * F
    Matrix Tn = T.pow(n - (k - 1));
    Matrix res = Tn * F;
    return res.a[0][0]; // a_n 位于结果矩阵第一行
}

