// 高斯消元模板（异或方程组/模方程组通用）
template<typename T>
struct GaussElimination {
    int n, m;           // n个方程，m个变量
    vector<vector<T>> a; // 增广矩阵 a[n][m+1]
    vector<T> ans;      // 解向量
    int rank;           // 矩阵的秩

    GaussElimination(int _n, int _m) : n(_n), m(_m) {
        a.assign(n, vector<T>(m+1, 0));
        ans.assign(m, 0);
    }

    // 添加方程系数
    void add_equation(int eq_id, const vector<T>& coeff, T constant) {
        for(int j = 0; j < m; j++) a[eq_id][j] = coeff[j];
        a[eq_id][m] = constant;
    }

    // 高斯消元求解
    int solve() {
        rank = 0;
        vector<int> where(m, -1); // 每个变量对应的主元行

        for(int col = 0, row = 0; col < m && row < n; col++) {
            // 寻找主元
            int pivot = row;
            for(int i = row; i < n; i++) {
                if(a[i][col] != 0) {
                    pivot = i;
                    break;
                }
            }
            if(a[pivot][col] == 0) continue;

            // 交换行
            swap(a[row], a[pivot]);
            where[col] = row;

            // 消元
            for(int i = 0; i < n; i++) {
                if(i != row && a[i][col] != 0) {
                    T factor = a[i][col] / a[row][col];
                    for(int j = col; j <= m; j++) {
                        a[i][j] -= factor * a[row][j];
                    }
                }
            }
            row++;
            rank++;
        }

        // 回代求解
        for(int j = 0; j < m; j++) {
            if(where[j] != -1) {
                ans[j] = a[where[j]][m] / a[where[j]][j];
            }
        }

        // 检查解的存在性
        for(int i = 0; i < n; i++) {
            T sum = 0;
            for(int j = 0; j < m; j++) {
                sum += ans[j] * a[i][j];
            }
            if(sum != a[i][m]) return 0; // 无解
        }

        // 计算自由变量个数
        int free_vars = m - rank;
        if(free_vars > 0) return 2; // 多解
        return 1; // 唯一解
    }

    // 对于异或方程组（GF(2)）的特化版本
    int solve_xor() {
        rank = 0;
        vector<int> where(m, -1);

        for(int col = 0, row = 0; col < m && row < n; col++) {
            // 寻找主元
            int pivot = -1;
            for(int i = row; i < n; i++) {
                if(a[i][col]) {
                    pivot = i;
                    break;
                }
            }
            if(pivot == -1) continue;

            // 交换行
            swap(a[row], a[pivot]);
            where[col] = row;

            // 消元
            for(int i = 0; i < n; i++) {
                if(i != row && a[i][col]) {
                    for(int j = col; j <= m; j++) {
                        a[i][j] ^= a[row][j];
                    }
                }
            }
            row++;
            rank++;
        }

        // 回代求解
        for(int j = 0; j < m; j++) {
            if(where[j] != -1) {
                ans[j] = a[where[j]][m];
            }
        }

        // 检查解的存在性
        for(int i = 0; i < n; i++) {
            int sum = 0;
            for(int j = 0; j < m; j++) {
                sum ^= (ans[j] & a[i][j]);
            }
            if(sum != a[i][m]) return 0;
        }

        return 1 << (m - rank); // 返回解的个数（2^{自由变量数}）
    }
};

// 线性基模板（处理异或空间）
struct LinearBasis {
    vector<long long> basis; // 存储线性基
    int size; // 基的大小

    LinearBasis(int max_bit = 60) { // 根据数据范围设定最大位数
        basis.resize(max_bit + 1, 0);
        size = 0;
    }

    // 插入元素，返回是否成功插入（即是否线性无关）
    bool insert(long long x) {
        for (int i = basis.size() - 1; i >= 0; i--) {
            if ((x >> i) & 1) {
                if (basis[i] == 0) {
                    basis[i] = x;
                    size++;
                    return true;
                }
                x ^= basis[i];
            }
        }
        return false;
    }

    // 判断x是否能被线性基表示
    bool check(long long x) {
        for (int i = basis.size() - 1; i >= 0; i--) {
            if ((x >> i) & 1) {
                if (basis[i] == 0) return false;
                x ^= basis[i];
            }
        }
        return true;
    }

    // 查询最大值（常用于异或和最大问题）
    long long query_max() {
        long long res = 0;
        for (int i = basis.size() - 1; i >= 0; i--) {
            if ((res ^ basis[i]) > res) {
                res ^= basis[i];
            }
        }
        return res;
    }

    // 查询最小值
    long long query_min() {
        for (int i = 0; i < basis.size(); i++) {
            if (basis[i] != 0) return basis[i];
        }
        return 0;
    }

    // 合并两个线性基
    void merge(const LinearBasis& other) {
        for (int i = other.basis.size() - 1; i >= 0; i--) {
            if (other.basis[i] != 0) {
                insert(other.basis[i]);
            }
        }
    }
};

