// 核心函数：计算游戏状态的 Grundy 数（SG 值）
int mex(unordered_set<int>& values) {
    int g = 0;
    while (values.find(g) != values.end()) g++;
    return g;
}

// 递归/DP 计算 SG 值（根据具体游戏规则实现）
int sg(int state) {
    // 如果状态已经计算过，直接返回
    if (dp[state] != -1) return dp[state];

    unordered_set<int> reachable;
    // 枚举所有可能的合法移动
    for (auto& move : possible_moves(state)) {
        int next_state = apply_move(state, move);
        reachable.insert(sg(next_state));
    }

    dp[state] = mex(reachable);
    return dp[state];
}

