    for (int i = 1; i <= n; i++) fact[i] = fact[i - 1] * i % MOD;
    inv_fact[n] = mod_pow(fact[n], MOD - 2);
    for (int i = n - 1; i >= 0; i--) inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD;
}
ll C(int n, int k) {
    if (k < 0 || k > n) return 0;
    return fact[n] * inv_fact[k] % MOD * inv_fact[n - k] % MOD;
}

// 容斥主函数
ll inclusion_exclusion() {
    // 1. 定义全集大小 total（通常为所有方案数）
    ll total = ...; 

    // 2. 定义需要排除的“坏事件”集合，通常用位掩码或子集枚举
    vector<ll> bad_events = ...; // 每个事件对应的方案数
    int m = bad_events.size();

    ll ans = total;
    // 3. 枚举所有非空子集（或特定组合），根据奇偶性加减
    for (int mask = 1; mask < (1 << m); mask++) {
        ll ways = ...; // 计算当前子集对应的事件同时发生的方案数
        int bits = __builtin_popcount(mask);
        // 奇减偶加（或根据题意调整符号）
        if (bits % 2 == 1) ans = (ans - ways + MOD) % MOD;
        else ans = (ans + ways) % MOD;
    }
    return ans;
}

// 不定方程非负整数解个数（带上限）
ll stars_and_bars_with_limits(vector<int>& limits, ll N) {
    // 方程 sum x_i = N, 0 <= x_i <= limits[i]
    int R = limits.size();
    ll total = C(N + R - 1, R - 1); // 无上限时的解数
    // 对每个违反上限的事件进行容斥
    for (int mask = 1; mask < (1 << R); mask++) {
        ll violated_sum = 0;
        int bits = 0;
        for (int i = 0; i < R; i++) {
            if (mask >> i & 1) {
                bits++;
                violated_sum += limits[i] + 1; // 至少取 limits[i]+1 个
            }
        }
        if (N - violated_sum >= 0) {
            ll ways = C(N - violated_sum + R - 1, R - 1);
            if (bits % 2 == 1) total = (total - ways + MOD) % MOD;
            else total = (total + ways) % MOD;
        }
    }
    return total;
}

